import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  content: string;
  createdAt: Date;
};

// In-memory store for demo purposes.
const store: Post[] = [
  {
    id: '1',
    title: 'Hello World',
    content: 'Welcome to the blog!',
    createdAt: new Date('2026-07-16'),
  },
];

export function addPost(title: string, content: string): Post {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: new Date(),
  };
  store.push(post);
  return post;
}

export const getPosts = unstable_cache(
  async () => {
    // Intentionally slow to demonstrate caching — wait 2s
    // so the effect of revalidateTag is visible.
    await new Promise((resolve) => setTimeout(resolve, 2000));
    return [...store].sort(
      (a, b) => b.createdAt.getTime() - a.createdAt.getTime()
    );
  },
  ['posts-all'],
  { tags: ['posts'] }
);

'use server';

import { revalidateTag } from 'next/cache';
import { addPost } from './posts';

export type CreatePostResult =
  | { success: true }
  | { success: false; error: string };

export async function createPost(formData: FormData): Promise<CreatePostResult> {
  const title = formData.get('title')?.toString().trim();
  const content = formData.get('content')?.toString().trim();

  if (!title || !content) {
    return { success: false, error: 'Title and content are required.' };
  }

  if (title.length > 200) {
    return { success: false, error: 'Title must be 200 characters or fewer.' };
  }

  addPost(title, content);

  // Purge all cached data tagged 'posts' so the next page load
  // fetches fresh data instead of serving stale content.
  revalidateTag('posts');

  return { success: true };
}

import { createPost } from '@/lib/actions';
import { getPosts } from '@/lib/posts';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: 32, fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: 8 }}>Posts</h1>

      <form
        action={createPost}
        style={{
          display: 'flex',
          flexDirection: 'column',
          gap: 12,
          padding: 16,
          border: '1px solid #ddd',
          borderRadius: 8,
          marginBottom: 32,
        }}
      >
        <h2 style={{ margin: 0 }}>Create a Post</h2>
        <input
          name="title"
          placeholder="Title"
          required
          style={{ padding: 8, fontSize: 16 }}
        />
        <textarea
          name="content"
          placeholder="Content"
          required
          rows={4}
          style={{ padding: 8, fontSize: 16, resize: 'vertical' }}
        />
        <button
          type="submit"
          style={{
            padding: '8px 16px',
            fontSize: 16,
            background: '#0066cc',
            color: '#fff',
            border: 'none',
            borderRadius: 6,
            cursor: 'pointer',
            alignSelf: 'flex-start',
          }}
        >
          Create
        </button>
      </form>

      <section>
        {posts.length === 0 ? (
          <p>No posts yet.</p>
        ) : (
          <ul style={{ listStyle: 'none', padding: 0, display: 'flex', flexDirection: 'column', gap: 16 }}>
            {posts.map((post) => (
              <li
                key={post.id}
                style={{
                  padding: 16,
                  border: '1px solid #eee',
                  borderRadius: 8,
                }}
              >
                <h3 style={{ margin: '0 0 4px' }}>{post.title}</h3>
                <p style={{ margin: 0, color: '#555' }}>{post.content}</p>
                <small style={{ color: '#999' }}>
                  {post.createdAt.toLocaleDateString()}
                </small>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}

